import{_ as s,c as e,o as t,V as i}from"./chunks/framework.yBzoR3F1.js";const k=JSON.parse('{"title":"git subtree 推送指定文件夹到指定分支","description":"","frontmatter":{"title":"git subtree 推送指定文件夹到指定分支","date":"2022-11-23","category":"工程化","tags":["git"]},"headers":[],"relativePath":"pages/posts/git-subtree.md","filePath":"pages/posts/git-subtree.md"}'),a={name:"pages/posts/git-subtree.md"},p=i(`<h1 id="git-subtree-推送指定文件夹到指定分支" tabindex="-1">git subtree 推送指定文件夹到指定分支 <a class="header-anchor" href="#git-subtree-推送指定文件夹到指定分支" aria-label="Permalink to &quot;git subtree 推送指定文件夹到指定分支&quot;">​</a></h1><p>假如，某个 git 项目有三个平行的目录 <code>p1/</code>、<code>p2/</code>、<code>p3/</code>。随着开发进程的推移，发现这三个目录的代码或文件的关联度很低，实际上是各自独立的。这时可以使用 p1proj、p2proj、p3proj 这三个分支来进行管理，而原来的 master 分支继续保留。</p><p><code>git subtree</code> 就适合这种通过分支来管理文件的情况：</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> subtree push --prefix p1 origin p1proj</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> subtree push --prefix p2 origin p2proj</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> subtree push --prefix p3 origin p3proj</span></span></code></pre></div><p>最常见的场景是写 vitepress 文档，通常文档的位置在项目的 <code>docs/.vitepress/dist</code> 目录中，并且文档部署的地方是 Github 中的 gh-pages 分支。</p><p>那么可以执行下面命令，将 dist 目录推送到 gh-pages 分支：</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> subtree push --prefix docs/.vitepress/dist origin gh-pages</span></span></code></pre></div><p>此时，项目有 master 分支和 gh-pages 分支，并且 gh-pages 分支使用的是 master 分支中的部分文件，所以当修改了 master 中的文档并提交之后，再推送一下 gh-pages 分支，两边代码就能保持一致了。</p>`,8),r=[p];function o(n,h,g,d,c,l){return t(),e("div",null,r)}const _=s(a,[["render",o]]);export{k as __pageData,_ as default};
